// 原始循环结构：i -> j -> k
// 优化后：j -> i -> k (分块)
#pragma scop
for (jj = 0; jj < _PB_N; jj += TILE_N) {
  int j_end = min(jj + TILE_N, _PB_N);
  for (i = 0; i < _PB_M; i++) {
    for (j = jj; j < j_end; j++) {
      DATA_TYPE temp = B[i][j];
      for (k = i+1; k < _PB_M; k++) {
        temp += A[k][i] * B[k][j];
      }
      B[i][j] = alpha * temp;
    }
  }
}
#pragma endscop
// 建议TILE_N设为L1缓存行大小/数据类型的倍数

// 对j循环进行向量化
#pragma omp simd
for (j = jj; j < j_end; j++) {
  temp[j-jj] = B[i][j];
}
for (k = i+1; k < _PB_M; k++) {
  DATA_TYPE a_val = A[k][i];
  #pragma omp simd
  for (j = jj; j < j_end; j++) {
    temp[j-jj] += a_val * B[k][j];
  }
}
